{
  "learning_outcomes": [
    {
      "unit_name": "Unit 1",
      "chapter_name": "Some Basic Concepts of Chemistry",
      "topic": "Fundamental Chemical Concepts and Stoichiometry",
      "outcomes": [
        "Apply laws of chemical combination and Dalton's Atomic Theory",
        "Perform mole concept calculations and determine percentage composition",
        "Execute stoichiometric calculations with uncertainty analysis"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Structure of Atom",
      "topic": "Atomic Structure and Quantum Models",
      "outcomes": [
        "Trace the discovery of sub-atomic particles and their properties",
        "Evaluate the development leading to Bohr's Model and its limitations",
        "Apply the Quantum Mechanical Model of the atom"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Classification of Elements and Periodicity in Properties",
      "topic": "Periodicity and Element Classification",
      "outcomes": [
        "Apply the Modern Periodic Law to organize elements",
        "Correlate electronic configuration with element types (s-, p-, d-, f- blocks)",
        "Predict periodic trends in properties of elements"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Bonding and Molecular Structure",
      "topic": "Chemical Bonding and Molecular Architecture",
      "outcomes": [
        "Apply Kossel-Lewis approach to explain ionic and covalent bonding",
        "Use VSEPR theory to predict molecular geometry",
        "Analyze bonding using Valence Bond Theory and Molecular Orbital Theory",
        "Evaluate the role of hydrogen bonding in molecular structure"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Thermodynamics",
      "topic": "Thermodynamic Principles in Chemistry",
      "outcomes": [
        "Define thermodynamic terms and apply them to chemical processes",
        "Calculate enthalpy changes for different types of reactions",
        "Determine reaction spontaneity using Gibbs Energy"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Equilibrium",
      "topic": "Chemical Equilibrium Dynamics",
      "outcomes": [
        "Apply the Law of Chemical Equilibrium to calculate equilibrium constants",
        "Analyze the relationship between K, Q, and Gibbs Energy",
        "Predict shifts in equilibrium due to changes in concentration or conditions"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Redox Reactions",
      "topic": "Redox Reaction Mechanisms",
      "outcomes": [
        "Classify reactions as oxidation or reduction based on classical and electron transfer definitions",
        "Determine oxidation numbers and balance redox equations"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Organic Chemistry: Some basic Principles and Techniques",
      "topic": "Organic Chemistry Fundamentals",
      "outcomes": [
        "Represent organic compounds using structural formulas",
        "Apply nomenclature rules to classify organic compounds",
        "Identify isomerism and analyze reaction mechanisms"
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Hydrocarbons",
      "topic": "Hydrocarbon Chemistry",
      "outcomes": [
        "Classify hydrocarbons into alkanes, alkenes, alkynes, and aromatics",
        "Analyze the relationship between structure and reactivity"
      ]
    },
    {
      "unit_name": "Unit 2",
      "chapter_name": "D. Chemical Equilibrium",
      "topic": "Chemical and Ionic Equilibrium Systems",
      "outcomes": [
        "Distinguish between physical and chemical processes in equilibrium",
        "Calculate and apply the Law of Chemical Equilibrium and Equilibrium Constant (K)",
        "Analyze the relationship between Reaction Quotient (Q), Equilibrium Constant (K), and Gibbs Energy (G)",
        "Predict factors affecting equilibria in homogeneous and heterogeneous systems",
        "Apply ionic equilibrium concepts to acids, bases, buffer solutions, and solubility"
      ]
    },
    {
      "unit_name": "Unit 3",
      "chapter_name": "E. Quantitative Estimation",
      "topic": "Quantitative Estimation and Volumetric Analysis",
      "outcomes": [
        "Use mechanical/electronic balances for accurate mass measurement",
        "Prepare standard solutions of oxalic acid and sodium carbonate",
        "Determine solution strength via titration against standard solutions"
      ]
    },
    {
      "unit_name": "Unit 4",
      "chapter_name": "F. Qualitative Analysis",
      "topic": "Qualitative Analysis of Inorganic and Organic Compounds",
      "outcomes": [
        "Identify one anion and one cation from a given salt sample",
        "Detect Nitrogen, Sulphur, and Chlorine in organic compounds"
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "PROJECTS",
      "topic": "Laboratory Techniques and Safety",
      "outcomes": [
        "Cut, bend, and draw glass tubes and rods safely",
        "Bore corks for experimental setups"
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "PROJECTS",
      "topic": "Characterization and Purification Methods",
      "outcomes": [
        "Determine melting and boiling points of organic compounds",
        "Perform crystallization techniques for purification"
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "PROJECTS",
      "topic": "pH Analysis and Acid-Base Chemistry",
      "outcomes": [
        "Determine pH of various solutions using indicators",
        "Study pH changes during titration and common-ion effects"
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "PROJECTS",
      "topic": "Chemical Equilibrium Investigation",
      "outcomes": [
        "Study the shift in equilibrium between ferric ions and thiocyanate ions",
        "Analyze concentration changes affecting cobalt complex equilibria"
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "PROJECTS",
      "topic": "Scientific Investigation and Project Work",
      "outcomes": [
        "Investigate bacterial contamination in drinking water",
        "Study methods of water purification",
        "Analyze regional variations in water hardness and ion presence",
        "Evaluate foaming capacity of soaps and effect of additives",
        "Study acidity of tea leaves, fruits, and vegetables",
        "Determine rates of evaporation for different liquids",
        "Assess the effect of acids/bases on fiber tensile strength"
      ]
    }
  ]
}
